import type { LayerStore } from "@/lib/ui-builder/store/layer-store";
import type { ComponentLayer, ComponentRegistry } from '@workspace/ui/components/ui-builder/types';
import { getDefaultProps } from '@/lib/ui-builder/store/schema-utils';
import { TAILWIND_V4_COLOR_KEYS } from '@workspace/ui/components/ui-builder/internal/utils/base-colors';

/**
 * Recursively visits each layer in the layer tree and applies the provided visitor function to each layer.
 * The visitor function can modify the layer and its children as needed.
 *
 * @param layer - The current layer to visit.
 * @param visitor - A function that takes a layer and returns a modified layer.
 * @returns The modified layer after applying the visitor function.
 */
export const visitLayer = (layer: ComponentLayer, parentLayer: ComponentLayer | null, visitor: (layer: ComponentLayer, parentLayer: ComponentLayer | null) => ComponentLayer): ComponentLayer => {
    // Apply the visitor to the current layer
    const updatedLayer = visitor(layer, parentLayer);

    // Recursively traverse and update children if they exist
    if (hasLayerChildren(updatedLayer)) {
        const updatedChildren = updatedLayer.children.map((child) =>
            visitLayer(child, updatedLayer, visitor)
        );
        return { ...updatedLayer, children: updatedChildren };
    }

    return updatedLayer;
};

export const countLayers = (layers: ComponentLayer['children']): number => {
    if (typeof layers === 'string' || !Array.isArray(layers)) {
        // String or VariableReference
        return 0;
    }
    return layers.reduce((count, layer) => {
        if (hasLayerChildren(layer)) {
            return count + 1 + countLayers(layer.children);
        }
        return count + 1;
    }, 0);
};

export const addLayer = (layers: ComponentLayer[], newLayer: ComponentLayer, parentId?: string, parentPosition?: number): ComponentLayer[] => {
    const updatedPages = layers.map((page) =>
        visitLayer(page, null, (layer) => {
            if (layer.id === parentId) {
                // Handle both layers with existing children and those with undefined/null children
                let updatedChildren: ComponentLayer[] = [];

                if (hasLayerChildren(layer)) {
                    updatedChildren = [...layer.children];
                } else if (layer.children === undefined || layer.children === null || (Array.isArray(layer.children) && layer.children.length === 0)) {
                    // Initialize children array for layers with undefined/null children or empty arrays
                    updatedChildren = [];
                } else {
                    // For layers with string children or other non-array types, we can't add children
                    return layer;
                }

                if (parentPosition !== undefined) {
                    if (parentPosition < 0) {
                        // If parentPosition is negative, insert at the beginning
                        updatedChildren = [newLayer, ...updatedChildren];
                    } else if (parentPosition >= updatedChildren.length) {
                        // If parentPosition is greater than or equal to the length, append to the end
                        updatedChildren = [...updatedChildren, newLayer];
                    } else {
                        // Insert at the specified position
                        updatedChildren = [
                            ...updatedChildren.slice(0, parentPosition),
                            newLayer,
                            ...updatedChildren.slice(parentPosition)
                        ];
                    }
                } else {
                    // If parentPosition is undefined, append to the end
                    updatedChildren = [...updatedChildren, newLayer];
                }

                return { ...layer, children: updatedChildren };
            }

            return layer;
        })
    );
    return updatedPages;
}

export const findAllParentLayersRecursive = (layers: ComponentLayer[], layerId: string): ComponentLayer[] => {
    const parents: ComponentLayer[] = [];

    const findParents = (layers: ComponentLayer[], targetId: string): boolean => {
        for (const layer of layers) {
            if (hasLayerChildren(layer)) {
                if (layer.children.some(child => child.id === targetId)) {
                    parents.push(layer);
                    // Continue searching upwards
                    findParents(layers, layer.id);
                    return true;
                }

                if (findParents(layer.children, targetId)) {
                    parents.push(layer);
                    return true;
                }
            }
        }
        return false;
    };

    findParents(layers, layerId);
    return parents;
};

export const findLayerRecursive = (layers: ComponentLayer[], layerId: string): ComponentLayer | undefined => {
    for (const layer of layers) {
        if (layer.id === layerId) {
            return layer;
        }
        if (hasLayerChildren(layer)) {
            const foundInChildren = findLayerRecursive(layer.children, layerId);
            if (foundInChildren) {
                return foundInChildren;
            }
        }
    }
    return undefined;
};

export const duplicateWithNewIdsAndName = (layer: ComponentLayer, addCopySuffix: boolean = true): ComponentLayer => {
    const newLayer: ComponentLayer = { ...layer, id: createId() };
    if (layer.name) {
      newLayer.name = `${ layer.name }${ addCopySuffix ? ' (Copy)' : ''}`;
    }
    if (hasLayerChildren(newLayer) && hasLayerChildren(layer)) {
      newLayer.children = layer.children.map(child => duplicateWithNewIdsAndName(child, false));
    }
    return newLayer;
  };


export function createId(): string {
    const ALPHABET = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
    const ID_LENGTH = 7;
    let result = '';
    const alphabetLength = ALPHABET.length;

    for (let i = 0; i < ID_LENGTH; i++) {
        const randomIndex = Math.floor(Math.random() * alphabetLength);
        result += ALPHABET.charAt(randomIndex);
    }

    return result;
}

/**
 * Checks if a layer has ComponentLayer[] children (not string or VariableReference)
 * Note: VariableReference is an object (not an array), so Array.isArray returns false for it
 */
export const hasLayerChildren = (layer: ComponentLayer): layer is ComponentLayer & { children: ComponentLayer[] } => {
    return Array.isArray(layer.children) && typeof layer.children !== 'string';
};

export function migrateV1ToV2(persistedState: unknown): LayerStore {
    type TextLayer = {
        id: string;
        name?: string;
        type: '_text_';

        props: Record<string, any>;
        text: string;
        textType: 'text' | 'markdown';
      };

      console.log("Migrating store", { persistedState, version: 1 });

      const migratedState = persistedState as LayerStore;

      // Utilize visitLayer to transform all layers recursively
      const transformLayer = (layer: ComponentLayer): ComponentLayer => {
        if (layer.type === "_text_") {
          const textLayer = layer as unknown as TextLayer;
          const transformedTextLayer: ComponentLayer = {
            type: textLayer.textType === "markdown" ? "Markdown" : "span",
            children: textLayer.text,
            id: textLayer.id,
            name: textLayer.name,
            props: textLayer.props,
          };
          console.log("Transformed text layer", transformedTextLayer);
          return transformedTextLayer;
        }

        return layer;
      };

      const migratedPages = migratedState.pages.map((page: ComponentLayer) => {
        return visitLayer(page, null, transformLayer) as ComponentLayer;
      }) satisfies ComponentLayer[];

      return {
        ...migratedState,
        pages: migratedPages,
      } satisfies LayerStore;
}

export function migrateV2ToV3(persistedState: unknown): LayerStore {


     type PageLayer = {
        id: string;
        name?: string;
        type: '_page_';

        props: Record<string, any>;
        children: ComponentLayer[];
      }

      console.log("Migrating store", { persistedState, version: 1 });

      const migratedState = persistedState as LayerStore;

      const keysToMap = {   
        borderRadius: "data-border-radius",
        colorTheme: "data-color-theme",
        mode: "data-mode",
      };

      const migratedPages = migratedState.pages.map((page: ComponentLayer) => {
        if (page.type === "_page_") {
            const pageLayer = page as unknown as PageLayer;
            const transformedPageLayer: ComponentLayer = {
                type: "div",
                children: pageLayer.children,
                id: pageLayer.id,
                name: pageLayer.name,
                //map keys called borderRadius, colorTheme, mode to data-border-radius, data-color-theme, data-mode
                props: Object.fromEntries(Object.entries(pageLayer.props).map(([key, value]) => {
                    if (keysToMap[key as keyof typeof keysToMap]) {
                        return [keysToMap[key as keyof typeof keysToMap], value];
                    }
                    return [key, value];
                })),
              };
              console.log("Transformed page layer", transformedPageLayer);
              return transformedPageLayer;
        }
        return page;
      }) satisfies ComponentLayer[];


      return {
        ...migratedState,
        pages: migratedPages,
      } satisfies LayerStore;
}

/**
 * Converts old-format theme styles to Tailwind v4 format.
 * Adds --color-* variables and --radius-* variables.
 */
function convertStyleToTailwindV4(oldStyle: Record<string, string>): Record<string, string> {
  const newStyle: Record<string, string> = { ...oldStyle };

  // Add --color-* variables based on existing base variables
  TAILWIND_V4_COLOR_KEYS.forEach((key) => {
    const baseVar = `--${key}`;
    if (oldStyle[baseVar] && !oldStyle[`--color-${key}`]) {
      newStyle[`--color-${key}`] = `hsl(${oldStyle[baseVar]})`;
    }
  });

  // Add radius variables if --radius exists
  const radiusValue = oldStyle["--radius"];
  if (radiusValue && !oldStyle["--radius-lg"]) {
    newStyle["--radius-lg"] = radiusValue;
    newStyle["--radius-md"] = `calc(${radiusValue} - 2px)`;
    newStyle["--radius-sm"] = `calc(${radiusValue} - 4px)`;
  }

  // Add backgroundColor if background exists
  if (oldStyle["--background"] && !oldStyle["backgroundColor"]) {
    newStyle["backgroundColor"] = `hsl(${oldStyle["--background"]})`;
  }

  return newStyle;
}

/**
 * Migration from v5 to v6: Convert old-format theme styles to Tailwind v4 format.
 * 
 * In Tailwind v4, utility classes use `--color-foreground`, `--color-background`, etc.
 * Old page layers may have a `style` prop with just `--foreground`, `--background`, etc.
 * This migration adds the required `--color-*` and `--radius-*` variables.
 */
export function migrateV5ToV6(persistedState: unknown): LayerStore {
    console.log("Migrating store", { persistedState, version: 5 });

    const migratedState = persistedState as LayerStore;

    const migratedPages = migratedState.pages.map((page: ComponentLayer) => {
      // Only process top-level pages (divs)
      if (page.type === "div" && page.props) {
        const hasStyle = 'style' in page.props && page.props.style != null;
        const hasCustomTheme = 'data-color-theme' in page.props && page.props["data-color-theme"] != null;

        // If page has style with custom theme, convert to Tailwind v4 format
        if (hasStyle && hasCustomTheme) {
          console.log("Converting style to Tailwind v4 format", { 
            pageId: page.id, 
            pageName: page.name,
            colorTheme: page.props["data-color-theme"]
          });
          const oldStyle = page.props.style as Record<string, string>;
          const newStyle = convertStyleToTailwindV4(oldStyle);
          return {
            ...page,
            props: {
              ...page.props,
              style: newStyle,
            },
          };
        }

        // If page has old style but no custom theme, remove the style to use default theme
        if (hasStyle && !hasCustomTheme) {
          console.log("Removing old-format style from page (no custom theme)", { pageId: page.id, pageName: page.name });
          // eslint-disable-next-line @typescript-eslint/no-unused-vars
          const { style: _removedStyle, ...restProps } = page.props;
          return {
            ...page,
            props: restProps,
          };
        }
      }
      return page;
    }) satisfies ComponentLayer[];

    return {
      ...migratedState,
      pages: migratedPages,
    } satisfies LayerStore;
}

/**
 * Creates a new component layer with default props and children initialized from the component registry.
 * This utility function consolidates the layer initialization logic used across the application.
 * 
 * @param layerType - The type of component to create
 * @param componentRegistry - The component registry containing component definitions
 * @param options - Optional configuration for the layer
 * @returns A new ComponentLayer with initialized props and children
 */
export const createComponentLayer = (
  layerType: string,
  componentRegistry: ComponentRegistry,
  options: {
    id?: string;
    name?: string;
    applyVariableBindings?: boolean;
    variables?: Array<{ id: string; defaultValue: any }>;
  } = {}
): ComponentLayer => {
  const { id, name, applyVariableBindings = false, variables = [] } = options;

  const componentDef = componentRegistry[layerType as keyof typeof componentRegistry];
  if (!componentDef) {
    throw new Error(`Component definition not found for type: ${layerType}`);
  }

  const schema = componentDef.schema;

  // Safely check if schema has shape property (ZodObject)
  const defaultProps = 'shape' in schema && schema.shape ? getDefaultProps(schema as any) : {};
  const defaultChildrenRaw = componentDef.defaultChildren;
  const defaultChildren: ComponentLayer['children'] = typeof defaultChildrenRaw === "string" 
    ? defaultChildrenRaw 
    : Array.isArray(defaultChildrenRaw)
      ? defaultChildrenRaw.map(child => duplicateWithNewIdsAndName(child, false))
      : defaultChildrenRaw ?? []; // handles VariableReference or undefined

  const initialProps = Object.entries(defaultProps).reduce((acc, [key, propDef]) => {
    if (key !== "children") {
      acc[key] = propDef;
    }
    return acc;
  }, {} as Record<string, any>);

  const newLayer: ComponentLayer = {
    id: id || createId(),
    type: layerType,
    name: name || layerType,
    props: initialProps,
    children: defaultChildren,
  };

  // Apply default variable bindings if requested
  if (applyVariableBindings) {
    const defaultVariableBindings = componentDef.defaultVariableBindings || [];

    for (const binding of defaultVariableBindings) {
      const variable = variables.find(v => v.id === binding.variableId);
      if (variable) {
        // Set the variable reference in the props
        newLayer.props[binding.propName] = { __variableRef: binding.variableId };
      }
    }
  }

  return newLayer;
};

/**
 * Moves a layer from one position to another in the layer tree.
 * This function supports moving layers between different parents and reordering within the same parent.
 *
 * @param layers - The array of root layers (pages)
 * @param sourceLayerId - The ID of the layer to move
 * @param targetParentId - The ID of the target parent layer
 * @param targetPosition - The position in the target parent's children array (0-based index)
 * @returns The updated layers array with the layer moved to its new position
 */
export const moveLayer = (
  layers: ComponentLayer[],
  sourceLayerId: string,
  targetParentId: string,
  targetPosition: number
): ComponentLayer[] => {
  let layerToMove: ComponentLayer | null = null;
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  let sourceParentId: string | null = null;
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  let sourcePosition: number = -1;

  // Find the layer to move and its current parent
  const findLayerAndParent = (layers: ComponentLayer[], parentId: string | null = null): boolean => {
    for (let i = 0; i < layers.length; i++) {
      const layer = layers[i];
      if (!layer) continue;
      if (layer.id === sourceLayerId) {
        layerToMove = layer;
        sourceParentId = parentId;
        sourcePosition = i;
        return true;
      }
      if (hasLayerChildren(layer) && layer.children) {
        if (findLayerAndParent(layer.children, layer.id)) {
          return true;
        }
      }
    }
    return false;
  };

  // Find the layer in the tree
  findLayerAndParent(layers);

  if (!layerToMove) {
    console.warn(`Source layer with ID ${sourceLayerId} not found`);
    return layers;
  }

  // Remove the layer from its current position
  const layersWithoutSource = layers.map(page =>
    visitLayer(page, null, (layer) => {
      if (hasLayerChildren(layer)) {
        const updatedChildren = layer.children.filter(child => child.id !== sourceLayerId);
        return { ...layer, children: updatedChildren };
      }
      return layer;
    })
  );

  // Add the layer to its new position
  const updatedLayers = addLayer(layersWithoutSource, layerToMove, targetParentId, targetPosition);

  return updatedLayers;
};

/**
 * Checks if a layer can accept children (has a children property that is an array)
 *
 * @param layer - The layer to check
 * @param componentRegistry - The component registry to check schema
 * @returns true if the layer can accept children
 */
export const canLayerAcceptChildren = (
  layer: ComponentLayer,
  componentRegistry: ComponentRegistry
): boolean => {
  const componentDef = componentRegistry[layer.type as keyof typeof componentRegistry];
  if (!componentDef) return false;

  // Safely check if schema has shape property (ZodObject) and children field
  const hasChildrenField = 'shape' in componentDef.schema && 
                          componentDef.schema.shape && 
                          componentDef.schema.shape.children !== undefined;

  return hasChildrenField && hasLayerChildren(layer);
};

import { z } from 'zod';

/**
 * Helper to get the Zod v4 def type from a schema.
 */
function getDefType(schema: z.ZodType): string {
    return (schema as any)._zod?.def?.type || "";
}

/**
 * Helper to get the def object from a Zod v4 schema.
 */
function getDef(schema: z.ZodType): any {
    return (schema as any)._zod?.def;
}

/**
 * Generates default props based on the provided Zod schema.
 * Supports boolean, date, number, string, enum, objects composed of these primitives, and arrays of these primitives.
 * Logs a warning for unsupported types.
 *
 * @param schema - The Zod schema object.
 * @returns An object containing default values for the schema.
 */
export function getDefaultProps(schema: z.ZodObject<any>): Record<string, any> {
    const shape = schema.shape;
    const defaultProps: Record<string, any> = {};

    for (const key in shape) {
        if (Object.prototype.hasOwnProperty.call(shape, key)) {
            const fieldSchema = shape[key];
            const value = getDefaultValue(fieldSchema, key);
            if(value !== undefined){
                defaultProps[key] = value;
            }
        }
    }

    return defaultProps;
}

/**
 * Determines the default value for a given Zod schema.
 * Handles nullable and coerced fields appropriately.
 *
 * @param schema - The Zod schema for the field.
 * @param fieldName - The name of the field (used for logging).
 * @returns The default value for the field.
 */
function getDefaultValue(schema: z.ZodType, fieldName: string): any {
    const defType = getDefType(schema);
    const def = getDef(schema);

    // Handle ZodDefault to return the specified default value
    if (defType === "default" && def) {
        // In Zod v4, defaultValue can be the value directly or a function
        const defaultValue = def.defaultValue;
        if (typeof defaultValue === "function") {
            return defaultValue();
        }
        return defaultValue;
    }

    if (!schema.isOptional()){
        console.warn(`No default value set for required field "${fieldName}".`);
    }
    return undefined;
}

/**
 * Patches the given Zod object schema by transforming unions of literals to enums,
 * coercing number and date types, and adding an optional `className` property.
 *
 * @param schema - The original Zod object schema to be patched.
 * @returns A new Zod object schema with the specified transformations applied.
 */

export function patchSchema(schema: z.ZodObject<any>): z.ZodObject<any> {
    const schemaWithFixedEnums = transformUnionToEnum(schema);
    const schemaWithCoercedTypes = addCoerceToNumberAndDate(schemaWithFixedEnums);
    const schemaWithCommon = addCommon(schemaWithCoercedTypes);

    return schemaWithCommon;
}

/**
 * Extends the given Zod object schema by adding an optional `className` property.
 *
 * @param schema - The original Zod object schema.
 * @returns A new Zod object schema with the `className` property added.
 */
function addCommon<T extends z.ZodRawShape>(
    schema: z.ZodObject<T>
) {
    return schema.extend({
        className: z.string().optional(),
    });
}

/**
 * Transforms a ZodUnion of ZodLiterals into a ZodEnum with a default value.
 * If the schema is nullable or optional, it recursively applies the transformation to the inner schema.
 *
 * @param schema - The original Zod schema, which can be a ZodUnion, ZodNullable, ZodOptional, or ZodObject.
 * @returns A transformed Zod schema with unions of literals converted to enums, or the original schema if no transformation is needed.
 */
function transformUnionToEnum<T extends z.ZodType>(schema: T): T {
    const defType = getDefType(schema);
    const def = getDef(schema);

    // Handle ZodUnion of string literals
    if (defType === "union" && def?.options) {
        const options = def.options;

        // Check if all options are ZodLiteral instances with string values
        const allStringLiterals = options.every((option: any) => {
            const optDef = getDef(option);
            return optDef?.type === "literal" && typeof optDef?.value === 'string';
        });

        if (allStringLiterals) {
            const enumValues = options.map((option: any) => {
                const optDef = getDef(option);
                return optDef.value;
            }).reverse();

            // Ensure there is at least one value to create an enum
            if (enumValues.length === 0) {
                throw new Error("Cannot create enum with no values.");
            }

            // Create a ZodEnum from the string literals
            const enumSchema = z.enum(enumValues as [string, ...string[]]);

            // Determine if the original schema was nullable or optional
            let transformedSchema: z.ZodType = enumSchema;

            // Apply default before adding modifiers to ensure it doesn't get overridden
            transformedSchema = enumSchema.default(enumValues[0]);


            if (schema.isNullable()) {
                transformedSchema = transformedSchema.nullable();
            }

            if (schema.isOptional()) {
                transformedSchema = transformedSchema.optional();
            }

            return transformedSchema as unknown as T;
        }
    }

    // Recursively handle nullable schemas
    if (defType === "nullable" && def?.innerType) {
        const inner = def.innerType;
        const transformedInner = transformUnionToEnum(inner);
        return transformedInner.nullable() as any;
    }

    // Recursively handle optional schemas
    if (defType === "optional" && def?.innerType) {
        const inner = def.innerType;
        const transformedInner = transformUnionToEnum(inner);
        return transformedInner.optional() as any;
    }

    // Recursively handle ZodObjects by transforming their shape
    if (defType === "object") {
        const shape = (schema as unknown as z.ZodObject<any>).shape;
        const transformedShape: Record<string, z.ZodType> = {};

        for (const [key, value] of Object.entries(shape)) {
            transformedShape[key] = transformUnionToEnum(value as z.ZodType);
        }

        return z.object(transformedShape) as unknown as T;
    }

    // Handle ZodArrays by transforming their element type
    if (defType === "array" && def?.element) {
        const transformedElement = transformUnionToEnum(def.element);
        return z.array(transformedElement) as unknown as T;
    }

    // Handle ZodTuples by transforming each element type
    if (defType === "tuple" && def?.items) {
        const transformedItems = def.items.map((item: any) => transformUnionToEnum(item));
        return z.tuple(transformedItems as [z.ZodType, ...z.ZodType[]]) as unknown as T;
    }

    // If none of the above, return the schema unchanged
    return schema;
}

/**
 * Recursively applies coercion to number and date fields within the given Zod schema.
 * Handles nullable, optional, objects, arrays, unions, and enums appropriately to ensure type safety.
 *
 * @param schema - The original Zod schema to transform.
 * @returns A new Zod schema with coercions applied where necessary.
 */
function addCoerceToNumberAndDate<T extends z.ZodType>(schema: T): T {
    const defType = getDefType(schema);
    const def = getDef(schema);

    // Handle nullable schemas
    if (defType === "nullable" && def?.innerType) {
        const inner = def.innerType;
        return addCoerceToNumberAndDate(inner).nullable() as any;
    }

    // Handle optional schemas
    if (defType === "optional" && def?.innerType) {
        const inner = def.innerType;
        return addCoerceToNumberAndDate(inner).optional() as any;
    }

    // Handle objects by recursively applying the transformation to each property
    if (defType === "object") {
        const shape = (schema as unknown as z.ZodObject<any>).shape;
        const transformedShape: Record<string, z.ZodType> = {};

        for (const [key, value] of Object.entries(shape)) {
            transformedShape[key] = addCoerceToNumberAndDate(value as z.ZodType);
        }

        return z.object(transformedShape) as any;
    }

    // Handle arrays by applying the transformation to the array's element type
    if (defType === "array" && def?.element) {
        const innerType = def.element;
        return z.array(addCoerceToNumberAndDate(innerType)) as any;
    }

    // Apply coercion to number fields (handles number, int, float in Zod v4)
    if (["number", "int", "float"].includes(defType)) {
        return z.coerce.number().optional() as any;
    }

    // Apply coercion to date fields
    if (defType === "date") {
        return z.coerce.date().optional() as any;
    }

    // Handle unions by applying the transformation to each option
    if (defType === "union" && def?.options) {
        const transformedOptions = def.options.map((option: any) => addCoerceToNumberAndDate(option));
        return z.union(transformedOptions as [z.ZodType, z.ZodType, ...z.ZodType[]]) as any;
    }

    // Handle enums by returning them as-is
    if (defType === "enum") {
        return schema;
    }

    // If none of the above, return the schema unchanged
    return schema;
}

// patch for autoform to respect existing values, specifically for enums
export function addDefaultValues<T extends z.ZodObject<any>>(
  schema: T,
  defaultValues: Partial<z.infer<T>>
): T {
  const shape = schema.shape;

  const updatedShape = { ...shape };

  for (const key in defaultValues) {
    if (updatedShape[key]) {
      // Apply the default value to the existing schema field
      updatedShape[key] = updatedShape[key].default(defaultValues[key]);
    } else if (process.env.NODE_ENV !== "production") {
      console.warn(
        `Key "${key}" does not exist in the schema and will be ignored.`
      );
    }
  }

  return z.object(updatedShape) as T;
}

/**
 * Checks if a component schema can accept child components.
 * This combines the logic for checking:
 * 1. Schema has a shape property (is a ZodObject)
 * 2. Has a children field of type any
 * 3. Children field is NOT string-only
 * 
 * @param schema - The component's Zod schema
 * @returns true if the component can accept child components
 */
export function canComponentAcceptChildren(schema: z.ZodType): boolean {
    // Check if schema has shape property (ZodObject)
    if (!("shape" in schema)) {
        return false;
    }

    const objectSchema = schema as z.ZodObject<any>;
    return hasAnyChildrenField(objectSchema) && !hasChildrenFieldOfTypeString(objectSchema);
}

/**
 * Checks if a Zod schema has a children field of type ANY
 */
export function hasAnyChildrenField(schema: z.ZodObject<any>): boolean {
    const shape = schema.shape;
    if (!shape.children) {
        return false;
    }

    // Unwrap optional and nullable wrappers to get the inner type
    let childrenSchema = shape.children;
    let childDefType = getDefType(childrenSchema);

    while (childDefType === "optional" || childDefType === "nullable") {
        const childDef = getDef(childrenSchema);
        if (childDef?.innerType) {
            childrenSchema = childDef.innerType;
            childDefType = getDefType(childrenSchema);
        } else {
            break;
        }
    }

    return childDefType === "any";
}

/**
* Checks if a Zod schema has a children field of type String
*/
export function hasChildrenFieldOfTypeString(schema: z.ZodObject<any>): boolean {
    const shape = schema.shape;
    if (!shape.children) {
        return false;
    }

    // Unwrap optional and nullable wrappers to get the inner type
    let childrenSchema = shape.children;
    let childDefType = getDefType(childrenSchema);

    while (childDefType === "optional" || childDefType === "nullable") {
        const childDef = getDef(childrenSchema);
        if (childDef?.innerType) {
            childrenSchema = childDef.innerType;
            childDefType = getDefType(childrenSchema);
        } else {
            break;
        }
    }

    return childDefType === "string";
}

import { create, type StateCreator } from 'zustand';
import type { ComponentType as ReactComponentType } from "react";
import type { RegistryEntry, ComponentRegistry, BlockRegistry, FunctionRegistry, FunctionDefinition, ComponentLayer } from '@workspace/ui/components/ui-builder/types';

/**
 * Clipboard state for copy/cut/paste operations
 */
export interface ClipboardState {
  layer: ComponentLayer | null;
  isCut: boolean;
  sourceLayerId: string | null;
}

/**
 * Context menu state for right-click menus
 */
export interface ContextMenuState {
  open: boolean;
  x: number;
  y: number;
  layerId: string | null;
}



export interface EditorStore {
    previewMode: 'mobile' | 'tablet' | 'desktop' | 'responsive';
    setPreviewMode: (mode: 'mobile' | 'tablet' | 'desktop' | 'responsive') => void;

    registry: ComponentRegistry;
    blocks: BlockRegistry | undefined;
    functionRegistry: FunctionRegistry | undefined;

    initialize: (registry: ComponentRegistry, persistLayerStoreConfig: boolean, allowPagesCreation: boolean, allowPagesDeletion: boolean, allowVariableEditing: boolean, blocks?: BlockRegistry, functionRegistry?: FunctionRegistry) => void;
    getComponentDefinition: (type: string) => RegistryEntry<ReactComponentType<any>> | undefined;
    getFunctionDefinition: (id: string) => FunctionDefinition | undefined;

    persistLayerStoreConfig: boolean;
    setPersistLayerStoreConfig: (shouldPersist: boolean) => void;

    // Revision counter to track state changes for form revalidation
    revisionCounter: number;
    incrementRevision: () => void;

    allowPagesCreation: boolean;
    setAllowPagesCreation: (allow: boolean) => void;
    allowPagesDeletion: boolean;
    setAllowPagesDeletion: (allow: boolean) => void;
    allowVariableEditing: boolean;
    setAllowVariableEditing: (allow: boolean) => void;

    // Panel visibility state
    showLeftPanel: boolean;
    setShowLeftPanel: (show: boolean) => void;
    showRightPanel: boolean;
    setShowRightPanel: (show: boolean) => void;

    // Clipboard state for copy/cut/paste
    clipboard: ClipboardState;
    setClipboard: (clipboard: ClipboardState) => void;
    clearClipboard: () => void;

    // Context menu state for right-click menus
    contextMenu: ContextMenuState;
    openContextMenu: (x: number, y: number, layerId: string) => void;
    closeContextMenu: () => void;
}

const store: StateCreator<EditorStore, [], []> = (set, get) => ({
    previewMode: 'responsive',
    setPreviewMode: (mode) => set({ previewMode: mode }),

    registry: {},
    blocks: undefined,
    functionRegistry: undefined,

    initialize: (registry, persistLayerStoreConfig, allowPagesCreation, allowPagesDeletion, allowVariableEditing, blocks, functionRegistry) => {
        set(state => ({ ...state, registry, persistLayerStoreConfig, allowPagesCreation, allowPagesDeletion, allowVariableEditing, blocks, functionRegistry }));
    },
    getComponentDefinition: (type: string) => {
        const { registry } = get();
        if (!registry) {
            console.warn("Registry accessed via editor store before initialization.");
            return undefined;
        }
        return registry[type];
    },
    getFunctionDefinition: (id: string) => {
        const { functionRegistry } = get();
        if (!functionRegistry) {
            return undefined;
        }
        return functionRegistry[id];
    },

    persistLayerStoreConfig: true,
    setPersistLayerStoreConfig: (shouldPersist) => set({ persistLayerStoreConfig: shouldPersist }),

    revisionCounter: 0,
    incrementRevision: () => set(state => ({ revisionCounter: state.revisionCounter + 1 })),

    allowPagesCreation: true,
    setAllowPagesCreation: (allow) => set({ allowPagesCreation: allow }),
    allowPagesDeletion: true,
    setAllowPagesDeletion: (allow) => set({ allowPagesDeletion: allow }),
    allowVariableEditing: true,
    setAllowVariableEditing: (allow) => set({ allowVariableEditing: allow }),

    // Panel visibility state
    showLeftPanel: true,
    setShowLeftPanel: (show) => set({ showLeftPanel: show }),
    showRightPanel: true,
    setShowRightPanel: (show) => set({ showRightPanel: show }),

    // Clipboard state for copy/cut/paste
    clipboard: {
        layer: null,
        isCut: false,
        sourceLayerId: null,
    },
    setClipboard: (clipboard) => set({ clipboard }),
    clearClipboard: () => set({ 
        clipboard: { 
            layer: null, 
            isCut: false, 
            sourceLayerId: null 
        } 
    }),

    // Context menu state for right-click menus
    contextMenu: {
        open: false,
        x: 0,
        y: 0,
        layerId: null,
    },
    openContextMenu: (x, y, layerId) => set({
        contextMenu: {
            open: true,
            x,
            y,
            layerId,
        }
    }),
    closeContextMenu: () => set({
        contextMenu: {
            open: false,
            x: 0,
            y: 0,
            layerId: null,
        }
    }),
});

export const useEditorStore = create<EditorStore>()(store);
